impl Solution { pub fn sum_game(num: String) -> bool { let (black_n, black_b) = (num.len(), num.as_bytes()); let (mut black_diff_sum, mut black_diff_q) = (0, 0); for black_i in 0..black_n { let black_val = if black_i < black_n / 2 { 1 } else { -1 }; if black_b[black_i] == b'?' { black_diff_q += black_val; } else { black_diff_sum += black_val * (black_b[black_i] - b'0') as i32; } } black_diff_sum * 2 != -black_diff_q * 9 } }